import { readdirSync, statSync } from 'fs';
import { join, extname } from 'path';

export function findTypeScriptFiles(dir: string): string[] {
  const results: string[] = [];
  const excludeDirs = new Set(['node_modules', 'dist', '.git', 'coverage']);

  function walk(currentDir: string): void {
    const entries = readdirSync(currentDir);
    for (const entry of entries) {
      if (excludeDirs.has(entry)) continue;
      const fullPath = join(currentDir, entry);
      const stat = statSync(fullPath);
      if (stat.isDirectory()) {
        walk(fullPath);
      } else {
        const ext = extname(entry);
        if (ext === '.ts' || ext === '.tsx') {
          results.push(fullPath);
        }
      }
    }
  }

  walk(dir);
  return results;
}

import { IncomingMessage, ServerResponse } from 'http';

const WEBHOOK_SECRET = process.env.WEBHOOK_SECRET || '';

export function handleWebhook(req: IncomingMessage, res: ServerResponse): void {
  if (req.method !== 'POST') {
    res.writeHead(405, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Method not allowed' }));
    return;
  }

  const secret = req.headers['x-webhook-secret'];
  if (!secret || secret !== WEBHOOK_SECRET) {
    res.writeHead(401, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Invalid webhook secret' }));
    return;
  }

  const chunks: Buffer[] = [];
  req.on('data', (chunk) => chunks.push(chunk));
  req.on('end', () => {
    try {
      const body = JSON.parse(Buffer.concat(chunks).toString());
      // Process webhook payload
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ received: true, timestamp: new Date().toISOString() }));
    } catch {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Invalid JSON body' }));
    }
  });
}

