describe('fetchWithTimeout', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it('resolves with response data on success', async () => {
    const mockResponse = { ok: true, json: () => Promise.resolve({ data: 'test' }) };
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue(mockResponse));

    const result = await fetchWithTimeout('https://api.example.com/data', 5000);
    expect(result).toEqual({ data: 'test' });
    expect(fetch).toHaveBeenCalledWith('https://api.example.com/data', expect.objectContaining({
      signal: expect.any(AbortSignal),
    }));
  });

  it('throws timeout error when request exceeds timeout', async () => {
    vi.stubGlobal('fetch', vi.fn().mockImplementation(() =>
      new Promise((_, reject) => {
        setTimeout(() => reject(new DOMException('Aborted', 'AbortError')), 100);
      })
    ));

    await expect(fetchWithTimeout('https://api.example.com/slow', 50))
      .rejects.toThrow();
  });

  it('throws on network error', async () => {
    vi.stubGlobal('fetch', vi.fn().mockRejectedValue(new TypeError('Failed to fetch')));

    await expect(fetchWithTimeout('https://unreachable.test', 5000))
      .rejects.toThrow('Failed to fetch');
  });

  it('throws on non-ok response', async () => {
    const mockResponse = { ok: false, status: 404, statusText: 'Not Found' };
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue(mockResponse));

    await expect(fetchWithTimeout('https://api.example.com/missing', 5000))
      .rejects.toThrow();
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { ReconnectionManager } from './ReconnectionManager';

describe('ReconnectionManager', () => {
  let manager: ReconnectionManager;
  let mockWs: any;

  beforeEach(() => {
    vi.useFakeTimers();
    mockWs = { close: vi.fn(), send: vi.fn(), readyState: 1 };
    vi.stubGlobal('WebSocket', vi.fn(() => mockWs));
    manager = new ReconnectionManager('ws://localhost:8080', { maxRetries: 3, baseDelay: 1000 });
  });

  afterEach(() => {
    vi.useRealTimers();
    vi.restoreAllMocks();
  });

  it('connects on initialization', () => {
    manager.connect();
    expect(WebSocket).toHaveBeenCalledWith('ws://localhost:8080');
  });

  it('reconnects automatically after unexpected close', () => {
    manager.connect();
    const onClose = (WebSocket as any).mock.results[0].value.onclose;
    onClose({ code: 1006 });
    vi.advanceTimersByTime(1000);
    expect(WebSocket).toHaveBeenCalledTimes(2);
  });

  it('applies exponential backoff between retries', () => {
    manager.connect();
    // First reconnect at 1000ms
    mockWs.onclose({ code: 1006 });
    vi.advanceTimersByTime(1000);
    expect(WebSocket).toHaveBeenCalledTimes(2);
    // Second reconnect at 2000ms
    mockWs.onclose({ code: 1006 });
    vi.advanceTimersByTime(1999);
    expect(WebSocket).toHaveBeenCalledTimes(2);
    vi.advanceTimersByTime(1);
    expect(WebSocket).toHaveBeenCalledTimes(3);
  });

  it('stops reconnecting after max retries', () => {
    manager.connect();
    for (let i = 0; i < 4; i++) {
      mockWs.onclose({ code: 1006 });
      vi.advanceTimersByTime(30000);
    }
    expect(WebSocket).toHaveBeenCalledTimes(4); // 1 initial + 3 retries
  });

  it('does not reconnect on intentional close (code 1000)', () => {
    manager.connect();
    mockWs.onclose({ code: 1000 });
    vi.advanceTimersByTime(10000);
    expect(WebSocket).toHaveBeenCalledTimes(1);
  });
});

