import { useState, useEffect, useCallback } from 'react';

interface UseLocalStorageOptions<T> {
  serializer?: (value: T) => string;
  deserializer?: (value: string) => T;
}

export function useLocalStorage<T>(
  key: string,
  initialValue: T,
  options?: UseLocalStorageOptions<T>
): [T, (value: T | ((prev: T) => T)) => void, () => void] {
  const serialize = options?.serializer ?? JSON.stringify;
  const deserialize = options?.deserializer ?? JSON.parse;

  const [storedValue, setStoredValue] = useState<T>(() => {
    if (typeof window === 'undefined') return initialValue;
    try {
      const item = window.localStorage.getItem(key);
      return item !== null ? deserialize(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = useCallback(
    (value: T | ((prev: T) => T)) => {
      setStoredValue((prev) => {
        const nextValue = value instanceof Function ? value(prev) : value;
        if (typeof window !== 'undefined') {
          try {
            window.localStorage.setItem(key, serialize(nextValue));
            window.dispatchEvent(new StorageEvent('storage', { key, newValue: serialize(nextValue) }));
          } catch { /* quota exceeded or private browsing */ }
        }
        return nextValue;
      });
    },
    [key, serialize]
  );

  const removeValue = useCallback(() => {
    if (typeof window !== 'undefined') {
      window.localStorage.removeItem(key);
    }
    setStoredValue(initialValue);
  }, [key, initialValue]);

  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key === key) {
        setStoredValue(e.newValue !== null ? deserialize(e.newValue) : initialValue);
      }
    };
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, [key, deserialize, initialValue]);

  return [storedValue, setValue, removeValue];
}

type EventMap = Record<string, (...args: any[]) => void>;

export class EventEmitter<Events extends EventMap> {
  private listeners = new Map<keyof Events, Set<Function>>();

  on<K extends keyof Events>(event: K, handler: Events[K]): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(handler);
    return () => this.off(event, handler);
  }

  off<K extends keyof Events>(event: K, handler: Events[K]): void {
    this.listeners.get(event)?.delete(handler);
  }

  emit<K extends keyof Events>(event: K, ...args: Parameters<Events[K]>): void {
    const handlers = this.listeners.get(event);
    if (!handlers) return;
    for (const handler of handlers) {
      try {
        handler(...args);
      } catch (error) {
        console.error(`Error in event handler for ${String(event)}:`, error);
      }
    }
  }

  once<K extends keyof Events>(event: K, handler: Events[K]): () => void {
    const wrapper = ((...args: any[]) => {
      this.off(event, wrapper as Events[K]);
      (handler as Function)(...args);
    }) as Events[K];
    return this.on(event, wrapper);
  }

  removeAllListeners(event?: keyof Events): void {
    if (event) {
      this.listeners.delete(event);
    } else {
      this.listeners.clear();
    }
  }
}

interface BuildResult {
  id: number;
  status: 'succeeded' | 'failed' | 'partiallySucceeded' | 'canceled';
  branch: string;
  durationMs: number;
  triggeredBy: string;
  finishedAt: string;
  definitionName: string;
}

export function parseBuildCompletionWebhook(payload: any): BuildResult | null {
  if (payload?.eventType !== 'build.complete') return null;

  const resource = payload.resource;
  if (!resource) return null;

  const startTime = new Date(resource.startTime).getTime();
  const finishTime = new Date(resource.finishTime).getTime();

  return {
    id: resource.id,
    status: resource.result as BuildResult['status'],
    branch: (resource.sourceBranch || '').replace('refs/heads/', ''),
    durationMs: finishTime - startTime,
    triggeredBy: resource.requestedFor?.displayName || 'unknown',
    finishedAt: resource.finishTime,
    definitionName: resource.definition?.name || 'unknown',
  };
}

function Watch-TypeCheck {
    param(
        [string]$Path = "./src",
        [int]$DebounceMs = 500
    )

    $watcher = New-Object System.IO.FileSystemWatcher
    $watcher.Path = (Resolve-Path $Path).Path
    $watcher.Filter = "*.ts"
    $watcher.IncludeSubdirectories = $true
    $watcher.EnableRaisingEvents = $true

    $lastRun = [DateTime]::MinValue
    $action = {
        $now = [DateTime]::Now
