        if ($elapsed -lt $DebounceMs) { return }
        $script:lastRun = $now
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Change detected: $($Event.SourceEventArgs.Name)" -ForegroundColor Cyan
        Start-Sleep -Milliseconds $DebounceMs
        & npx tsc --noEmit 2>&1 | ForEach-Object {
            if ($_ -match 'error TS') {
                Write-Host $_ -ForegroundColor Red
            } else {
                Write-Host $_ -ForegroundColor Gray
            }
        }
        if ($LASTEXITCODE -eq 0) {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Type check passed" -ForegroundColor Green
        } else {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Type check failed" -ForegroundColor Red
        }
    }

    Register-ObjectEvent $watcher Changed -Action $action | Out-Null
