    finally { $watcher.Dispose() }
}

interface WorkItem {
  id: number;
  title: string;
  state: string;
  parentId: number | null;
}

interface WorkItemNode {
  id: number;
  title: string;
  state: string;
  children: WorkItemNode[];
}

export function buildWorkItemTree(items: WorkItem[]): WorkItemNode[] {
  const nodeMap = new Map<number, WorkItemNode>();
  const roots: WorkItemNode[] = [];

  for (const item of items) {
    nodeMap.set(item.id, {
      id: item.id,
      title: item.title,
      state: item.state,
      children: [],
    });
  }

  for (const item of items) {
    const node = nodeMap.get(item.id)!;
    if (item.parentId === null || !nodeMap.has(item.parentId)) {
      roots.push(node);
    } else {
      nodeMap.get(item.parentId)!.children.push(node);
    }
  }

  return roots;
}

interface ModelfileConfig {
  from: string;
  system: string;
  parameters: Record<string, string | number>;
}

export function parseModelfile(content: string): ModelfileConfig {
  const fromMatch = content.match(/^\s*FROM\s+(\S+)/m);
  const from = fromMatch?.[1] ?? '';

  let system = '';
  const tripleQuote = content.match(/SYSTEM\s+"""([\s\S]*?)"""/m);
  if (tripleQuote) {
    system = tripleQuote[1].trim();
  } else {
    const singleQuote = content.match(/SYSTEM\s+"([^"]*)"/m);
    if (singleQuote) system = singleQuote[1].trim();
  }

  const parameters: Record<string, string | number> = {};
  const paramRegex = /^\s*PARAMETER\s+(\S+)\s+(.+)$/gm;
  let match: RegExpExecArray | null;
  while ((match = paramRegex.exec(content)) !== null) {
    const key = match[1];
    const raw = match[2].trim();
    const num = Number(raw);
    parameters[key] = Number.isFinite(num) ? num : raw;
  }

  return { from, system, parameters };
}

