export function compareSemver(a: string, b: string): -1 | 0 | 1 {
  const parseVersion = (v: string) => {
    const [version, prerelease] = v.split('-');
    const parts = version.split('.').map(Number);
    return { parts, prerelease: prerelease || null };
  };

  const va = parseVersion(a);
  const vb = parseVersion(b);

  for (let i = 0; i < 3; i++) {
    const pa = va.parts[i] || 0;
    const pb = vb.parts[i] || 0;
    if (pa > pb) return 1;
    if (pa < pb) return -1;
  }

  if (!va.prerelease && !vb.prerelease) return 0;
  if (!va.prerelease && vb.prerelease) return 1;
  if (va.prerelease && !vb.prerelease) return -1;

  const aParts = va.prerelease!.split('.');
  const bParts = vb.prerelease!.split('.');
  const len = Math.max(aParts.length, bParts.length);

  for (let i = 0; i < len; i++) {
    const ai = aParts[i];
    const bi = bParts[i];
    if (ai === undefined) return -1;
    if (bi === undefined) return 1;
    const aNum = Number(ai);
    const bNum = Number(bi);
    const aIsNum = Number.isFinite(aNum);
    const bIsNum = Number.isFinite(bNum);
    if (aIsNum && bIsNum) {
      if (aNum > bNum) return 1;
      if (aNum < bNum) return -1;
    } else if (aIsNum !== bIsNum) {
      return aIsNum ? -1 : 1;
    } else {
      if (ai > bi) return 1;
      if (ai < bi) return -1;
    }
  }

  return 0;
}

export async function* streamOllamaTokens(
  response: Response
): AsyncGenerator<string, void, undefined> {
  if (!response.ok) {
    throw new Error(`Ollama API error: ${response.status} ${response.statusText}`);
  }

  const reader = response.body?.getReader();
  if (!reader) {
    throw new Error('Response body is not readable');
  }

  const decoder = new TextDecoder();
  let buffer = '';

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() || '';

      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;
        try {
          const parsed = JSON.parse(trimmed);
          if (parsed.response) {
            yield parsed.response;
          }
          if (parsed.done) {
            return;
          }
        } catch {
          // Skip malformed JSON lines
        }
      }
    }

    if (buffer.trim()) {
      try {
        const parsed = JSON.parse(buffer.trim());
        if (parsed.response) yield parsed.response;
      } catch { /* ignore trailing partial */ }
    }
  } finally {
    reader.releaseLock();
  }
}

import { useState, useEffect } from 'react';

interface CountdownProps {
  targetDate: Date;
  expiredText?: string;
}

interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

export function Countdown({ targetDate, expiredText = 'Expired' }: CountdownProps) {
  const [timeLeft, setTimeLeft] = useState<TimeLeft | null>(null);
  const [expired, setExpired] = useState(false);

  useEffect(() => {
    function calculate() {
      const diff = targetDate.getTime() - Date.now();
      if (diff <= 0) {
        setExpired(true);
        setTimeLeft(null);
        return;
      }
      setTimeLeft({
        days: Math.floor(diff / (1000 * 60 * 60 * 24)),
        hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((diff / (1000 * 60)) % 60),
        seconds: Math.floor((diff / 1000) % 60),
      });
    }

    calculate();
    const interval = setInterval(calculate, 1000);
    return () => clearInterval(interval);
  }, [targetDate]);

  if (expired) {
    return <span className="text-red-500 font-semibold">{expiredText}</span>;
  }

  if (!timeLeft) return null;

  const pad = (n: number) => String(n).padStart(2, '0');

  return (
    <div className="flex gap-2 font-mono text-lg">
      <div className="flex flex-col items-center">
        <span className="text-2xl font-bold">{timeLeft.days}</span>
        <span className="text-xs text-gray-500">days</span>
      </div>
      <span className="text-2xl">:</span>
      <div className="flex flex-col items-center">
        <span className="text-2xl font-bold">{pad(timeLeft.hours)}</span>
        <span className="text-xs text-gray-500">hrs</span>
      </div>
      <span className="text-2xl">:</span>
      <div className="flex flex-col items-center">
        <span className="text-2xl font-bold">{pad(timeLeft.minutes)}</span>
        <span className="text-xs text-gray-500">min</span>
      </div>
      <span className="text-2xl">:</span>
      <div className="flex flex-col items-center">
        <span className="text-2xl font-bold">{pad(timeLeft.seconds)}</span>
        <span className="text-xs text-gray-500">sec</span>
      </div>
    </div>
  );
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { createRateLimiter } from './rateLimiter';

function mockReq(ip: string) {
  return { headers: { 'x-forwarded-for': ip }, socket: { remoteAddress: ip } } as any;
}

function mockRes() {
  const res: any = { statusCode: 200, headers: {} };
  res.setHeader = vi.fn((k: string, v: string) => { res.headers[k] = v; });
  res.end = vi.fn();
  res.json = vi.fn((data: any) => { res.body = data; });
  return res;
}

describe('rateLimiter', () => {
  beforeEach(() => vi.useFakeTimers());
  afterEach(() => vi.useRealTimers());

  it('allows requests under the limit', () => {
    const limiter = createRateLimiter({ maxRequests: 3, windowMs: 60000 });
    const req = mockReq('192.168.1.1');
    const next = vi.fn();

    for (let i = 0; i < 3; i++) {
      const res = mockRes();
      limiter(req, res, next);
    }

    expect(next).toHaveBeenCalledTimes(3);
  });

  it('blocks requests over the limit with 429', () => {
    const limiter = createRateLimiter({ maxRequests: 2, windowMs: 60000 });
    const req = mockReq('10.0.0.1');
    const next = vi.fn();

    limiter(req, mockRes(), next);
    limiter(req, mockRes(), next);

    const res = mockRes();
    limiter(req, res, next);

    expect(next).toHaveBeenCalledTimes(2);
    expect(res.statusCode).toBe(429);
  });

  it('resets counter after window expires', () => {
    const limiter = createRateLimiter({ maxRequests: 1, windowMs: 10000 });
    const req = mockReq('172.16.0.1');
    const next = vi.fn();

    limiter(req, mockRes(), next);
    expect(next).toHaveBeenCalledTimes(1);

    const res = mockRes();
    limiter(req, res, next);
    expect(res.statusCode).toBe(429);

    vi.advanceTimersByTime(10001);

    const res2 = mockRes();
    limiter(req, res2, next);
    expect(next).toHaveBeenCalledTimes(2);
  });

  it('tracks different IPs independently', () => {
    const limiter = createRateLimiter({ maxRequests: 1, windowMs: 60000 });
    const next = vi.fn();

    limiter(mockReq('1.1.1.1'), mockRes(), next);
    limiter(mockReq('2.2.2.2'), mockRes(), next);

    expect(next).toHaveBeenCalledTimes(2);
  });
});

